1	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
2	  const survivors: Array<[number, number]> = [];
3	  const liveCells = new Set(grid.map(([x, y]) => `${x},${y}`));
4	
5	  for (const [x, y] of grid) {
6	    let neighbors = 0;
7	    for (let dx = -1; dx <= 1; dx++) {
8	      for (let dy = -1; dy <= 1; dy++) {
9	        if (dx === 0 && dy === 0) continue;
10	        if (liveCells.has(`${x + dx},${y + dy}`)) {
11	          neighbors++;
12	        }
13	      }
14	    }
15	
16	    if (neighbors === 2) {
17	      survivors.push([x, y]);
18	    }
19	  }
20	
21	  return survivors;
22	}
